/* Evidence: cmem-worked-cmem-buffer-overflow-underflow-2 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 9472; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_buffer_overflow_underflow_2(unsigned char *buffer, size_t length, size_t from, size_t to, size_t count) {
  if (buffer == NULL || from > length || count > length - from) return 0;
  if (to > length || count > length - to) return 0;
  memmove(buffer + to, buffer + from, count);
  return 1;
}

int main(void) {
  unsigned char buffer[8] = { 0, 1, 2, 3, 4, 5, 6, 7 };
  int rejected = worked_cmem_buffer_overflow_underflow_2(buffer, 8, 7, 0, 2);
  int accepted = worked_cmem_buffer_overflow_underflow_2(buffer, 8, 1, 2, 4);
  int invariant = !rejected && accepted && buffer[2] == 1 && buffer[5] == 4 && 3 > 0;
  printf("move edge=%u invariant=%d\n", (unsigned)buffer[5], invariant);
  return invariant ? 0 : 1;
}

